/**
 * Generate the per-platform prebuild package manifests
 * (`packages/ai-gateway/npm/<triple>/package.json`) at the wrapper's version.
 *
 * Each prebuild package carries one file: the `alien-ai-gateway` launcher
 * binary for that platform, which `@alienplatform/ai-gateway` resolves and
 * spawns. The manifests are generated by the release pipeline rather than
 * checked in: every field is derived (the name, the wrapper's version, and the
 * platform selectors npm uses to pick the matching optional dependency), so a
 * checked-in copy would only add version-lockstep churn.
 *
 * The linux binaries are static musl builds, so a triple's `gnu` and `musl`
 * packages ship the same executable under two names: npm's `libc` selector
 * refuses to install a `glibc`-tagged package on Alpine, so both spellings
 * must exist for the loader's `platformTriple()` to resolve on either libc.
 */

import { mkdirSync, readFileSync, writeFileSync } from "node:fs"
import { join, resolve } from "node:path"
import { fileURLToPath } from "node:url"

const TRIPLES = [
  { triple: "darwin-arm64", os: "darwin", cpu: "arm64" },
  { triple: "darwin-x64", os: "darwin", cpu: "x64" },
  { triple: "linux-x64-gnu", os: "linux", cpu: "x64", libc: "glibc" },
  { triple: "linux-x64-musl", os: "linux", cpu: "x64", libc: "musl" },
  { triple: "linux-arm64-gnu", os: "linux", cpu: "arm64", libc: "glibc" },
  { triple: "linux-arm64-musl", os: "linux", cpu: "arm64", libc: "musl" },
]

const pkgDir = process.argv[2]
  ? resolve(process.argv[2])
  : fileURLToPath(new URL("..", import.meta.url))
const { version } = JSON.parse(readFileSync(join(pkgDir, "package.json"), "utf8"))

for (const { triple, os, cpu, libc } of TRIPLES) {
  const dir = join(pkgDir, "npm", triple)
  mkdirSync(dir, { recursive: true })
  const manifest = {
    name: `@alienplatform/ai-gateway-${triple}`,
    version,
    description: `The alien-ai-gateway launcher binary for ${triple}, resolved and spawned by @alienplatform/ai-gateway`,
    os: [os],
    cpu: [cpu],
    ...(libc ? { libc: [libc] } : {}),
    files: ["alien-ai-gateway"],
  }
  writeFileSync(join(dir, "package.json"), `${JSON.stringify(manifest, null, 2)}\n`)
  console.log(`Generated npm/${triple}/package.json at ${version}`)
}
